INSERT INTO prescription_examples (student_key, student_profile, workouts, workout_split) VALUES ('yasmin_de_nadai', '{"name":"Yasmin de Nadai","mapped_name":null,"birth_date":"1997-12-01","profession":"Arquiteta","sports_history":"Faço academia desde os 15 anos de idade, montados pelos profissionais da academia mesmo, mas sempre tive dificuldade de definição, o único período que vi diferença foi quando fiz treinos com acompanhamento de um personal e quando passei a seguir uma dieta. Ano passado, decidi fazer pilates 2x na semana por me sentir muito travada e acabei reduzindo a academia, o que teve um impacto no meu corpo, que afinou. Para esse ano, decidi ficar com o pilates apenas 1x na semana. Sempre achei que o cardio fosse me atrapalhar a ganhar massa mas passei a focar mais nele tem uns 2 anos e fez uma enorme diferença nos meus treinos de força, ampliou muito meu fôlego. Hoje, tento fazer 20min de cardio (caminhada 5km/h com inclinação 15%) ao fim de todo treino de força e correr 5km aos domingos (sem treino de musculação).","injuries":["Tenho um pouco de lordose mas desde que passei a fortalecer no pilates","não tive mais dores nos agachamentos. Ás vezes","sinto um pouco o joelho","mas parece mais ter a ver com erro na postura do que algo crônico."],"health_conditions":["Não tem."],"medications":["Não."],"current_practice":"Desde 2013/2014, basicamente musculação.","goal":"Atingir a estética que almejo. Gostaria de ganhar mais massa e definição, especialmente nos músculos das pernas e glúteos. Tenho um desenho de corpo onde minhas costas são mais largas que meus quadris, e que gostaria de equilibrar um pouco mais. Além disso, gostaria de ter maior entendimento da correta execução dos exercícios.","weekly_frequency":1,"session_duration":null,"gender":"F","experience_level":"intermediário","form_timestamp":"2025/01/13 1:24:11 PM GMT-3"}'::jsonb, '{"A":{"focus":"","exercises":[{"name":"Afundo Halteres c/ Step","method":"Tradicional","sets":1,"weight":"8.0","interval":"1''30\"","observations":"Colocar o step na frente e atrás resolveu a dor no joelho "},{"name":"Leg Horizontal","method":"Tradicional","sets":1,"reps":"12.0","weight":"92.5","interval":"1''30\""},{"name":"Cadeira Extensora","method":"Tradicional","sets":2,"reps":"14.0","weight":"45.0","interval":"1''"},{"name":"Cadeira Abdutora","method":"Tradicional","sets":2,"reps":"14.0","weight":"45.0","interval":"1''"}]},"B":{"focus":"","exercises":[{"name":"Remada Baixa Triângulo","method":"Tradicional","sets":1,"reps":"12.0","weight":"25.0","interval":"1''30\"","observations":"Puxar na região do umbigo"},{"name":"Crucifixo Inverso Máquina","method":"Tradicional","sets":2,"reps":"12.0","weight":"15.0","interval":"1''30\"","observations":"Abre o braço o máximo possível; braço alinhado com o ombro"},{"name":"Bíceps Banco 45°","method":"Tradicional","sets":1,"reps":"8.0","weight":"4.0","interval":"1''30\"","observations":"Inclinar um banco a 45°, deixar os braços para trás da linha do tronco (alongando os bíceps) e realizar a flexão dos cotovelos até os halteres chegarem próx aos ombros."}]},"C":{"focus":"","exercises":[{"name":"Stiff Barra","method":"Tradicional","sets":1,"reps":"12.0","weight":"Aprox. 30-40kg total","interval":"1''30","observations":"Quando esqueço a bandagem, preciso reduzir peso"},{"name":"Glúteo Coice Crossover","method":"Tradicional","sets":2,"reps":"12.0","weight":"10.0","interval":"1''30\"","observations":"Inclinar o tronco quase paralelo com o chão; trazer joelho ate passar da perna; no final girar o pé para fora"},{"name":"Recuo no Smith","method":"Tradicional","sets":1,"interval":"1''"},{"name":"Cadeira Flexora","method":"Tradicional","sets":1,"reps":"16.0","weight":"60.0","interval":"1''","observations":"Anotar a carga, realizar o máximo de peso possível para as 12-16 repetições. Deixando no máximo 2 repetições de reserva."}]},"D":{"focus":"","exercises":[{"name":"Elevação Lateral Halteres","method":"Tradicional","sets":2,"reps":"12.0","weight":"4.0","interval":"1''30\"","observations":"Braço lateral mesmo"},{"name":"FacePull Polia Alta (corda)","method":"Tradicional","sets":1,"weight":"Aprox 3 Blocos no Crossover","interval":"1''","observations":"Segurar a corda com as palmas das mãos voltadas uma a outra, realizar a puxada \"abrindo\" os cotovelos para os lados na altura dos ombros, focando bem no deltóide posterior"},{"name":"Panturrilha Máquina em Pé","method":"Tradicional","sets":1,"reps":"15.0","weight":"25.0","interval":"1''","observations":"Amplitude total"}]},"E":{"focus":"","exercises":[]}}'::jsonb, ARRAY['A','B','C','D']::TEXT[]) ON CONFLICT (student_key) DO UPDATE SET student_profile = EXCLUDED.student_profile, workouts = EXCLUDED.workouts, workout_split = EXCLUDED.workout_split;